section.codeblock:
firewall { 
    family inet { 
        filter temp { 
            term a { 
                from { 
                    source-address { 
                        10.0.0.1/32; 
                    } 
                    destination-address { 
                        10.0.0.2/32; 
                    } 
                    protocol icmp; 
                    icmp-type echo-request; 
                    source-port http; 
                    destination-port bgp; 
                    tcp-flags fin; 
                } 
                then { 
                    count c1; 
                    accept;           
                } 
            } 
        } 
    } 
}

firewall { 
    family inet6 { 
        filter temp6 { 
            term a { 
                from { 
                    source-address { 
                        2001:db8::1/128; 
                    } 
                    destination-address { 
                        2001:db8::1/128; 
                    } 
                    icmp-type echo-request; 
                    source-port http; 
                    destination-port bgp; 
                    tcp-flags fin; 
                } 
                then { 
                    count c1; 
                    discard;          
                } 
            } 
        } 
    } 
}

firewall { 
    family mpls { 
        filter temp_mpls { 
            term t1 { 
                from { 
                    exp 2-5;
                    label 1234-4321;
                } 
                then { 
                    accept;
                    count c1;
                    log;
                    syslog;          
                } 
            } 
        } 
    } 
}

user@host > show interfaces enp4s0   
unit 0 { 
    family inet { 
        filter { 
            input temp; 
        } 
        address 10.0.0.1/24; 
    } 
    family inet6 { 
        filter { 
            input temp6; 
        } 
    } 
}
